    "device-auth": {
      "name": "deviceAuth",
      "path": "/device-auth",
      "description": "Device Authorization Flow for CLI and programmatic clients (RFC 8628)",
      "actions": {
        "request": {
          "name": "request",
          "path": "/request",
          "method": "POST",
          "description": "Start a device authorization flow. Returns codes for the CLI to display and poll.",
          "bodySchema": {
            "type": "object",
            "properties": {
              "scopes": {
                "type": "array",
                "items": {
                  "type": "string"
                },
                "default": [
                  "read",
                  "write"
                ]
              },
              "keyName": {
                "type": "string",
                "minLength": 1,
                "maxLength": 100,
                "default": "CLI"
              }
            },
            "additionalProperties": false
          }
        },
        "info": {
          "name": "info",
          "path": "/info",
          "method": "GET",
          "description": "Get details of a device authorization request by user code. Used by the frontend authorize page."
        },
        "poll": {
          "name": "poll",
          "path": "/poll",
          "method": "POST",
          "description": "Check the status of a device authorization request. Returns the API key once approved.",
          "bodySchema": {
            "type": "object",
            "properties": {
              "deviceCode": {
                "type": "string",
                "minLength": 1
              }
            },
            "required": [
              "deviceCode"
            ],
            "additionalProperties": false
          }
        },
        "approve": {
          "name": "approve",
          "path": "/approve",
          "method": "POST",
          "description": "Approve or deny a pending device authorization request.",
          "bodySchema": {
            "type": "object",
            "properties": {
              "userCode": {
                "type": "string",
                "minLength": 1
              },
              "action": {
                "type": "string",
                "enum": [
                  "approve",
                  "deny"
                ]
              }
            },
            "required": [
              "userCode",
              "action"
            ],
            "additionalProperties": false
          }
        }
      }
    },
